/**
 * AlertProposal é um lembrete que o modelo de captura detectou dentro da nota.
 * FireAt é ISO 8601 com offset (como o modelo retornou); Recurrence é JSON
 * marshalado ou "". Presente só quando a nota tem horário/data concretos.
 */
export interface AlertProposal {
    "message": string;
    "fireAt": string;
    "recurrence": string;
}

/**
 * AskResult is /find plus an AI summary of the top notes.
 */
export interface AskResult {
    "status": string;
    "summary": string;
    "sources": SearchResult[] | null;
    "message": string;
    "tokens": number;
    "cost": number;
}

/**
 * AttachProposal points a capture at an existing note the model judged it
 * belongs to. Capture returns it (status "attach_proposed") instead of writing,
 * so the frontend can confirm before AppendTo runs.
 */
export interface AttachProposal {
    "targetId": number;
    "targetTitle": string;
}

/**
 * CaptureResult is what the frontend gets after a /note.
 * 
 * 	"created"    note stored
 * 	"no_api_key" the API key is missing
 * 	"error"      failure (see Message)
 */
export interface CaptureResult {
    "status": string;
    "noteId": number;
    "noteTitle": string;
    "content": string;
    "tags": string[] | null;
    "message": string;
    "tokens": number;
    "cost": number;

    /**
     * Count is how many notes resulted, set by the "split" overflow strategy.
     */
    "count": number;
    "alert": AlertProposal | null;
    "attach": AttachProposal | null;
    "overflow": OverflowProposal | null;
}

